    readonly memory: WebAssembly.Memory;
    readonly __wbg_rewoundamountshieldedoutput_free: (a: number, b: number) => void;
    readonly __wbg_rewoundfullshieldedoutput_free: (a: number, b: number) => void;
    readonly createAssetCommitment: (a: number, b: number, c: number, d: number) => [number, number, number, number];
    readonly createCommitment: (a: bigint, b: number, c: number, d: number, e: number) => [number, number, number, number];
    readonly createTrivialCommitment: (a: bigint, b: number, c: number) => [number, number, number, number];
    readonly deriveAssetTag: (a: number, b: number) => [number, number, number, number];
    readonly deriveEcdhSharedSecret: (a: number, b: number, c: number, d: number) => [number, number, number, number];
    readonly deriveTag: (a: number, b: number) => [number, number, number, number];
    readonly htrAssetTag: () => [number, number];
    readonly rewindAmountShieldedOutput: (a: number, b: number, c: number, d: number, e: number, f: number, g: number, h: number, i: number, j: number) => [number, number, number];
    readonly rewindFullShieldedOutput: (a: number, b: number, c: number, d: number, e: number, f: number, g: number, h: number, i: number, j: number) => [number, number, number];
    readonly rewoundamountshieldedoutput_blindingFactor: (a: number) => [number, number];
    readonly rewoundamountshieldedoutput_value: (a: number) => bigint;
    readonly rewoundfullshieldedoutput_assetBlindingFactor: (a: number) => [number, number];
    readonly rewoundfullshieldedoutput_blindingFactor: (a: number) => [number, number];
    readonly rewoundfullshieldedoutput_tokenUid: (a: number) => [number, number];
    readonly rewoundfullshieldedoutput_value: (a: number) => bigint;
    readonly rustsecp256k1zkp_v0_10_0_default_error_callback_fn: (a: number, b: number) => void;
    readonly rustsecp256k1zkp_v0_10_0_default_illegal_callback_fn: (a: number, b: number) => void;
    readonly rustsecp256k1_v0_10_0_context_create: (a: number) => number;
    readonly rustsecp256k1_v0_10_0_context_destroy: (a: number) => void;
    readonly rustsecp256k1_v0_10_0_default_error_callback_fn: (a: number, b: number) => void;
    readonly rustsecp256k1_v0_10_0_default_illegal_callback_fn: (a: number, b: number) => void;
    readonly __wbindgen_externrefs: WebAssembly.Table;
    readonly __wbindgen_malloc: (a: number, b: number) => number;
    readonly __externref_table_dealloc: (a: number) => void;
    readonly __wbindgen_free: (a: number, b: number, c: number) => void;
    readonly __wbindgen_start: () => void;
